    date: '',
    days: 5,
    budget: 'Comfortable',
    interests: []
  });

  // Gamification: Travel Score
  const [travelScore, setTravelScore] = useState(() => {
    const visited = JSON.parse(localStorage.getItem('visited_cities') || '[]');
    return visited.length;
  });

  // Voice Input Handler
  const handleVoiceInput = (field) => {
    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (SpeechRecognition) {
      const recognition = new SpeechRecognition();
      recognition.lang = 'en-US';
      recognition.start();
      recognition.onresult = (event) => {
        const transcript = event.results[0][0].transcript.replace(/\.$/, "");
        setTripDetails(prev => ({ ...prev, [field]: transcript }));
      };
    } else {
      alert("Voice input is not supported in this browser.");
    }
  };

  const interestsList = [
    { id: 'culture', label: 'Culture', icon: <Camera size={16} /> },
    { id: 'food', label: 'Food', icon: <Utensils size={16} /> },
    { id: 'music', label: 'Music', icon: <Music size={16} /> },
    { id: 'adventure', label: 'Adventure', icon: <Palmtree size={16} /> },
    { id: 'nightlife', label: 'Nightlife', icon: <Moon size={16} /> },
  ];

  const handleInterestToggle = (id) => {
    setTripDetails(prev => ({
      ...prev,
      interests: prev.interests.includes(id)
        ? prev.interests.filter(i => i !== id)
        : [...prev.interests, id]
    }));
  };

  const handleSearch = () => {
    // Navigate to results with all the data
    navigate(`/results?from=${tripDetails.from}&to=${tripDetails.to}&date=${tripDetails.date}&budget=${tripDetails.budget}`);
  };

  return (
    <div className="min-h-screen bg-gray-50 flex justify-center py-10 px-4">
