                >
                  <Minus size={20} />
                </button>
                <span className="text-2xl font-bold text-gray-800 w-8 text-center">{tripDetails.days}</span>
                <button
                  onClick={() => setTripDetails(prev => ({ ...prev, days: Math.min(30, prev.days + 1) }))}
