                        : 'bg-[#F4F1EB] border border-[#E8E4DC] text-[#1C1916] hover:border-[#B89A6A]/50'
                        }`}
                >
                    {isEditing ? <><Save size={14} /> Save Changes</> : <><Edit2 size={14} /> Edit Plan</>}
