                        </div>
                        <button onClick={() => window.open(data.routeUrl, '_blank')} className="bg-[#FDFCFA] text-[#1C1916] p-2.5 rounded-xl hover:scale-105 transition-transform shadow-lg">
                            <Navigation className="w-4 h-4" />
                        </button>
                    </div>
